"""
Standalone patch — writes mkt-context for Isaiah 24-28.
Run: python3 scripts/zc-context-isaiah-24-28-patch.py
Chapters: 24 (23v), 25 (12v), 26 (21v), 27 (13v), 28 (29v) = 98 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "24": {
    "1": "<p>Isaiah 24 opens the section modern scholars call the 'Isaiah Apocalypse' (chs. 24-27) — the most cosmically scoped section of the entire book. 'Hineh YHWH boqeq ha'arets uvoveleyha, behold the LORD is emptying/draining the earth and twisting its face.' The verb boqeq (to drain/empty, as one drains a bottle) describes the reversal of creation's filling — Gen 1:11-25 filled the earth with life; now YHWH empties it. 'Twisting its face' (uvoveleyha panim, and distorting her surface) = disfiguring the landscape. The universal scope: not a regional judgment but the whole earth (ha'arets, the land/earth). 'Scattering its inhabitants' (vehefits yosheveiha) = the reversal of the table-of-nations dispersal of Gen 10-11, now through divine judgment rather than linguistic confusion.</p>",
    "2": "<p>'It will be the same for people and priest, for servant and master, for maid and mistress, for buyer and seller, for lender and borrower, for creditor and debtor' — six pairs of social relationships, all erased by universal judgment. The six pairs cover the entire social spectrum: religious hierarchy (priest/people), household hierarchy (servant/master, maid/mistress), economic relationships (buyer/seller, lender/borrower, creditor/debtor). The Jubilee year (Lev 25) temporarily suspended economic hierarchies as a sign of covenant restoration; here the suspension is permanent and judicial, not celebratory. The cosmic judgment levels all social differentiation — death is the great equalizer (Eccl 9:2: 'the same destiny overtakes all').</p>",
    "3": "<p>'The earth will be completely stripped bare and completely ransacked — for the LORD has spoken' — the double emphatic: 'hibboq tibboq ha'arets vehibboz tibboz, stripped bare it will be stripped bare, plundered it will be plundered.' The absolute infinitive construction (verb + cognate infinitive) in Hebrew creates an unqualified declaration of certainty. 'For YHWH has spoken this word' (ki YHWH diber et-haddavar hazeh) — the divine word guarantees the outcome. The stripping of the earth is both ecological (land depopulated) and economic (all accumulated wealth removed). The earth that accumulated productivity over millennia is stripped to nothing.</p>",
    "4": "<p>'The earth mourns and withers; the world droops and fades; the high and mighty of the earth wither away' — the earth itself mourning: 'avelah navlah ha'arets, the earth mourns and withers/languishes.' The verbs are paired: aval (to mourn, with the physical drooping of grief) and naval (to wither/fade, the botanical dying of unwatered plants). 'The world droops and fades' (umlelah navlah tevel, the world languishes and withers). The 'high and mighty' (merom am ha'arets, the height of the people of the earth = the exalted ones) also wither — the social height that seemed most immune to judgment also withers. The mourning earth is personified as a grieving community whose grief mirrors its physical withering.</p>",
    "5": "<p>'The earth lies polluted beneath its inhabitants, because they have violated the laws, broken the ordinances, and shattered the everlasting covenant' — the theological ground for the ecological judgment: 'ki-charfu tora, for they have transgressed the laws/Torah' (charfu = transgressed/violated, related to cheref = reproach), 'chalfu choq, they have broken the statute' (chalfu = replaced/violated), 'heferu berit olam, they have broken/annulled the everlasting covenant.' The 'everlasting covenant' (berit olam) can refer to the Noahic covenant (Gen 9:16 — no more destruction by flood), the Abrahamic (Gen 17:7), or the creation covenant itself. The earth 'polluted' (chanefah, defiled/polluted — the same root as 10:6's godless/polluted) by its inhabitants echoes Num 35:33 ('bloodshed pollutes the land, and no atonement can be made for the land on which blood has been shed').</p>",
    "6": "<p>'Therefore a curse is consuming the earth, and its inhabitants suffer the punishment they deserve; therefore the earth's population is burned up and only a remnant survives' — the curse-mechanism: 'al-ken alah akhilah erets, therefore a curse devours the earth.' The alah (curse = the covenant oath-curse of Deut 29:19-27: 'the LORD's wrath and jealousy will burn against him; the curses written in this book will fall on him') consumes the earth. 'Veyesh-mu yoshevei vah, and the inhabitants of it bear their punishment/are desolate.' The remnant: 'venishtear enosh miz'ar, and humans are left, small in number' — the remnant theology applied universally: even in the comprehensive curse, a remnant survives.</p>",
    "7": "<p>'The new wine dries up, the vine withers, and all the joyful sigh with grief' — the suspension of fermentation: 'aval tirosh umlelah gefen, the new wine mourns, the vine withers/languishes.' The new wine (tirosh, the fresh grape-juice, the first product of the harvest = the symbol of firstfruits blessing) is itself mourning — the liquid that was the marker of festive joy now as grief-stricken as the people. The vine (gefen, the cultivated vine of the covenant — Isa 5:1-7 the vineyard song; Ps 80:8-16 Israel as YHWH's vine) withers. 'All the joyful of heart (kol-simche lev) sigh with grief' (ne'enach, groan).</p>",
    "8": "<p>'The joyful beating of tambourines stops; the shouting of the revellers ends; the happy strumming of the harp goes silent' — the three instruments of festive celebration silenced: 'shavat mesos tupim, the joy of tambourines has ceased' (the tof/tambourine was the percussion instrument of the Miriam's celebration, Exod 15:20; harvest festivals). 'Chadal sheon alozim, the uproar of the jubilant has ended.' 'Shavat mesos kinnor, the joy of the harp has ceased.' The harp (kinnor, David's instrument, 1 Sam 16:23) silenced. The comprehensive end of music = the end of covenant community life — Ps 137:2: 'We hung our harps on the poplars... how can we sing the LORD's song in a foreign land?'</p>",
    "9": "<p>'They drink no more wine to the sound of songs; strong drink turns bitter on the tongue' — the corruption of the senses: wine without music and the bitterness of strong drink. 'Beshir lo yishtu-yayin, with song they will not drink wine' — the communal wine-drinking with song (the symposium of festive celebration) ends. 'Yimar shekhar leshoteav, strong drink (shekhar = barley beer/palm wine) will be bitter to those who drink it.' The sensory pleasure of drink is reversed: what was pleasurable becomes bitter. The bitterness may be physical (the taste of anxiety and grief) or metaphorical (joy transformed to mourning).</p>",
    "10": "<p>'The city of chaos lies in ruins; every house is barred so that no one can enter' — the 'city of chaos' (qiryat tohu, the city of formlessness/void). The tohu (formlessness, emptiness) of Gen 1:2 (tohu vavohu, formless and void) applied to the fallen city: the city has reverted to pre-creation chaos. 'Nishbar kol-bayit mibo, every house is shut up from entry' — the city whose gates and houses functioned as social gathering points (gates for commerce and judgment; houses for hospitality) now barred shut. The social space of the city = community; barred houses = the end of community.</p>",
    "11": "<p>'In the streets there is a cry for wine; all joy has turned to gloom; the gladness of the earth is driven into exile' — the street-cry for wine: 'tse'aqah al-hayayin bachutsot, a cry for wine in the streets' — the desperate longing for what has been removed. 'Arevah kol-simchah, all joy has become dark/gloom' (arav = to grow dark/evening). 'Galah mesos ha'arets, the gladness of the earth is exiled/has gone into exile.' The word galah (to go into exile) is the covenant-judgment word for deportation: Israel's gladness has itself gone into exile, as the people will go into exile.</p>",
    "12": "<p>'Nothing remains in the city but devastation, and the gate is smashed to rubble' — the final state of the fallen city: 'nish'ar ba'ir shoammah, what remains in the city is desolation' (shammah = astonishment/waste). 'Veshafon yoqqe sha'ar, and the gate is battered to ruins' — the gate (sha'ar) as the social, commercial, and judicial center of the ancient city (Ruth 4:1-12: legal transactions at the gate; Prov 31:23: 'her husband is respected at the city gate'). When the gate is 'beaten to ruin' (yoqqe, smashed/hammered), the entire social fabric of the city collapses.</p>",
    "13": "<p>'For this is how it will be across the whole earth, among all the peoples — like what remains after the olive harvest, like the few grapes left after the vintage' — the remnant imagery applied globally: 'ki-khoh yihyeh beqerev ha'arets betokh haammim, for thus it will be in the midst of the earth, among the peoples.' The two agricultural gleaning images: 'kenoph zayit, like the gleaning of the olive harvest' (the few olives that remain on the branches after the main harvest) and 'kavolalot im-kallah betsiyr hagefen, like the grape gleaning when the vintage is done' (the straggler grapes left after the pickers). The same remnant imagery as 17:6 (two or three olives at the branch top). Universal judgment leaves a tiny remnant.</p>",
    "14": "<p>'The survivors raise their voices and sing; they shout from the west over the LORD's majesty' — the unexpected singing of the remnant: 'hemmah yis'u qolam yaronu, they will lift their voices, they will shout for joy.' The survivors of the universal judgment break into praise 'bege'on YHWH, over the majesty/excellence of YHWH.' The survivors sing 'from the sea' (meyam, from the sea/west = from the Mediterranean coastlands) — the westernmost survivors shout for joy. The theological logic: even in universal judgment, those who survive recognize YHWH's justice and majesty and respond with praise. The praise comes from the extremities of the earth (west in v.14, east in v.15).</p>",
    "15": "<p>'Therefore in the eastern regions, give glory to the LORD; in the coastlands of the sea exalt the name of the LORD, the God of Israel' — the universal praise extended east: 'ba'urim kabbdu YHWH, in the east/lights glorify YHWH.' The ba'urim (in the lights/regions of the dawn = the east) corresponds to the sea/west of v.14 — both extremities of the known world called to glorify YHWH. 'In the coastlands of the sea' (ba'iyei hayam, in the islands/coastlands of the sea) — the Mediterranean island-world (Greece, Cyprus, the Aegean). 'The name of the LORD, the God of Israel' — YHWH specifically as the God of Israel is the object of universal praise, even from regions with no prior covenant relationship.</p>",
    "16": "<p>'From the ends of the earth we hear singing: Glory to the Righteous One! But I say, I am wasting away — I am wasting away! Disaster is upon me! The treacherous keep betraying; the traitors have utterly betrayed!' — the prophet's internal conflict: universal praise from 'the ends of the earth' (mikkanaf ha'arets, from the wing/edge of the earth) — 'Tsevi latsaddiq, glory to the Righteous One!' But the prophet himself says: 'Razziti razziti, I am wasting away, wasting away.' The tension: the prophet hears the eschatological praise but is not yet there; he remains in the present reality of treachery. 'Bogdim bagadu ubeghed begadim, the treacherous keep betraying and with great treachery have the treacherous betrayed' — the fourfold repetition of betrayal (boged) mirrors the universal scope of the judgment he has been describing.</p>",
    "17": "<p>'Terror and the pit and the trap are coming for you, O inhabitants of the earth!' — the triple terror: pachad vaphachat vapach (terror and pit and snare) = a deliberate Hebrew sound-wordplay on three near-homophones. The fear, the pit, and the snare are the three threats that cannot all be evaded: one who flees the fear falls into the pit; one who climbs out of the pit is caught in the snare. The three-stage inescapability describes the comprehensive nature of divine judgment — there is no escape route that leads to safety. Jer 48:43-44 quotes this passage almost verbatim in the Moab oracle.</p>",
    "18": "<p>'Whoever runs from the sound of terror will fall into the pit, and whoever climbs out of the pit will be caught in the trap — for the floodgates of heaven are flung open and the foundations of the earth are shaking' — the Noah flood imagery: 'ki aarubbot mimmarom niftechu, for the windows of heaven are opened' — the same 'windows of heaven' as Gen 7:11 ('the floodgates of the sky were opened') when Noah's flood began. 'Vayirash'u mosedei aretz, and the foundations of the earth shake' — the cosmic foundations are destabilized (Ps 18:7: 'the earth trembled and quaked; the foundations of the mountains shook'). The judgment of the Isaiah Apocalypse exceeds even the Noahic flood: the flood was water from above; here both heaven-windows open AND earth-foundations shake.</p>",
    "19": "<p>'The earth is completely shattered; the earth is split wide open; the earth is violently convulsed' — the triple intensification of the earth's collapse: 'ro'a hit-ro'ah ha'arets, the earth is broken, utterly broken' (absolute infinitive emphatic); 'por hitporah ha'arets, the earth is split, utterly split'; 'mot hitmotah ha'arets, the earth is shaken, utterly shaken.' The three verbs with their repeated absolute infinitives create a staccato rhythm of catastrophe. The earth that was YHWH's ordered creation (Gen 1) is now comprehensively disordered. This triple earth-destruction is the cosmic backdrop against which the resurrection hope of 26:19 shines — the same earth that collapses will 'give birth to its dead.'</p>",
    "20": "<p>'The earth reels like a drunk; it sways like a flimsy shelter; its rebellion weighs it down until it collapses and does not rise again' — the earth as a drunk and a shelter. 'Nua tanua ha'arets kashikkor, the earth staggers, staggers like a drunk' — the same drunk-imagery as the corrupt priests of 28:7-8, now applied to the entire earth. 'Vehitnodedah kamelunahm, and it sways like a night-hut' (melunah = a watchman's temporary shelter, a flimsy booth). 'Ukhaved aleha pish'ah venaphlah velo-tosif qum, and heavy upon her is her transgression and she falls and will not rise again.' The earth's covenant violation (v.5) is the weight that causes the final fall — the earth falls under its own moral weight, like a drunkard who can no longer stand.</p>",
    "21": "<p>'In that day the LORD will call to account the powers above in the heavens, and the kings of the earth here below' — the cosmic scope of divine accountability: 'yifqod YHWH al-tseva hamerom bammarom ve'al-malkhei ha'adamah al-ha'adamah, YHWH will visit/punish the host of the height in the height, and the kings of the ground on the ground.' The 'host of the height' (tseva hamerom) = the heavenly/spiritual powers behind the nations — the 'princes' of Dan 10:13, 20-21 (the prince of Persia, the prince of Greece) who are spiritual powers governing nations. Eph 6:12 identifies the same reality: 'rulers, authorities, powers of this dark world, spiritual forces of evil in the heavenly realms.' Both the spiritual powers (above) and the human kings (below) face the same divine accountability simultaneously.</p>",
    "22": "<p>'They will be herded like prisoners into a pit, locked up in a dungeon, and after many long days they will be called to account' — the imprisonment of cosmic powers: 've'usfuh asfat al-bor, and they will be gathered, gathered into a pit' (double verb for thoroughness). 'Vesuggeru al-masgger, and they will be shut up in prison' (masgger = the dungeon/lock-up). 'Umerov yamim yippaqedhu, and after many days they will be visited/punished.' The interim imprisonment of the rebellious powers before final judgment echoes 2 Pet 2:4 ('God did not spare angels when they sinned but sent them to Tartarus, putting them in chains of darkness to be held for judgment') and Jude 6 ('the angels who did not keep their proper domain, he has kept in eternal chains under darkness for the judgment').</p>",
    "23": "<p>'Then the moon will be put to shame and the sun confounded, for the LORD of hosts will reign on Mount Zion and in Jerusalem, and his glory will shine before his elders' — the eschatological climax: 'vachefrah halevana uvosheshah hachammah, the moon will be put to shame and the sun will be abashed/confounded.' The two great luminaries created to give light (Gen 1:14-16) are outshone by YHWH's own glory — the luminaries are made redundant when the divine light appears (Rev 21:23: 'the city does not need the sun or the moon to shine on it, for the glory of God gives it light'). 'Ki-malakh YHWH tseva'ot behar Tsiyon uviYerushalayim, for YHWH of hosts reigns on Mount Zion and in Jerusalem.' The divine council of 'his elders' (zekenaiv, his elders) echoes Exod 24:9-11 (Moses, Aaron, Nadab, Abihu, and 70 elders who saw God on Sinai and ate and drank before him).</p>"
  },
  "25": {
    "1": "<p>Isaiah 25:1 opens the communal thanksgiving song that responds to the cosmic judgment of ch.24. 'YHWH attah Eli, LORD, you are my God; I will exalt you; I will praise your name.' The personal covenant declaration 'you are my God' (attah Eli) is the foundational covenant formula (Exod 3:6; Hos 2:23; Jer 31:33). 'For you have done wonderful things' (ki asita pele, for you have done wonderful/miraculous things) — pele (wonder/miracle) is the same root as pele yo'ets (Wonderful Counselor) of 9:6. 'Plans formed long ago, faithful and true' (etsot merachok emunah omen, plans from afar, faithfulness, truth) — the long-range divine purposes, faithful (emunah, trustworthy) and true (omen, reliable/steadfast). YHWH's historical acts fulfill what he planned before history.</p>",
    "2": "<p>'For you have turned a city into a heap of rubble, a fortified city into a ruin; the stronghold of foreigners is a city no longer — it will never be rebuilt' — the city of divine judgment. 'Ki samta me'ir lagal, for you have turned a city into a heap of rubble' — the undefined city may be Babylon (ch.13-14), Samaria (722 BCE), Nineveh (612 BCE), or the eschatological 'city of chaos' of 24:10. 'Armon zarim me'ir le'olam lo yibbaneh, the palace/stronghold of foreigners is a city no longer; it will never be rebuilt forever.' The permanent non-rebuilding echoes the Babylon oracle of 13:20 ('it will never be inhabited again') and contrasts with Jerusalem's permanent establishment (25:6: 'on this mountain').</p>",
    "3": "<p>'Therefore strong peoples will glorify you; cities of ruthless nations will stand in awe of you' — the universal response to YHWH's victory: 'al-ken yekabbedukha am-az, therefore a strong people will honor you.' The 'strong people' (am-az, the fierce/powerful people) = the very nations that had been the instruments of oppression now honoring YHWH. 'Qiryat goyim aritsim yira'ukha, the city of ruthless nations will fear you.' The ruthless nations' cities (aritsim, the terrifying/violent ones) standing in awe (yira'ukha, will fear you) = the reversal of the fear-dynamic: those who inspired terror in others now tremble before YHWH.</p>",
    "4": "<p>'For you have been a refuge for the poor, a refuge for the needy in their distress, a shelter from the storm, a shade from the scorching heat. The blast of the ruthless is like a driving rainstorm against a wall' — YHWH's specific care for the vulnerable articulated. 'Ki-hayita maoz ledal, for you have been a refuge to the poor.' The four protective roles: maoz (stronghold/refuge for the poor), maoz le'evyon (refuge for the needy), machaseh mizzerem (shelter from the storm), tsel mecheorev (shade from the heat). The protective images cover both weather extremes: storm (zarem, the driving rainstorm) and heat (chorev, scorching heat). 'The blast of the ruthless' (ruach aritsim = breath/spirit/wind of the violent ones) is 'like a driving rainstorm against a wall' (kezorem qir, like a winter storm against a wall) — the wall YHWH provides deflects the storm.</p>",
    "5": "<p>'You silence the clamor of the foreigners as drought is broken by cloud-shadow; you subdue the triumph of the ruthless' — the divine reduction of threatening noise: 'ke'orev chorev tsal av, like the drought-heat broken by cloud-shadow.' The cloud-shadow that suddenly moderates oppressive heat is the image for YHWH silencing/moderating the 'clamor of the foreigners' (sheon zarim, the noise/tumult of strangers). 'Zimrat aritsim ta'aneh, the song of the ruthless you will humble/silence' (ta'aneh, can mean both 'answer' and 'humble/bend down'). The victory song of the violent is reduced to humble silence before YHWH's power.</p>",
    "6": "<p>'On this mountain the LORD of hosts will prepare a feast for all peoples — a feast of rich food and well-aged wines, of choice meat full of marrow, of the finest strained vintages' — the eschatological banquet on Mount Zion: 'veasah YHWH tseva'ot lekhol-haammim bahar hazeh, YHWH of hosts will make for all peoples on this mountain.' 'A feast of rich food' (mishte shemanim, a feast of fattened things — the finest cuts, full marrow) and 'well-aged wines' (mishte shemarim, a feast of aged wines — wines settled on their lees for maximum richness). The feast 'for all peoples' (lekhol-haammim) = universal invitation, not just Israel. Rev 19:9 ('Blessed are those invited to the wedding supper of the Lamb') and Matt 22:1-14 (wedding banquet parable) draw on this. The choice food and aged wine represent the full covenant satisfaction — the shalom of abundance shared universally.</p>",
    "7": "<p>'On this mountain he will destroy the shroud that is cast over all peoples, the sheet that is spread over all nations' — the shroud/burial cloth as the death-covering over all humanity. 'Billa et-penei hallot haluot al-kol-haammim, he will swallow/destroy the surface of the shroud covering all peoples.' The hallot (shroud/veil) and massekha (woven covering) are the burial wrappings of death. Death has covered all peoples with the same burial cloth — the universal mortality that has been humanity's fate since Gen 3:19 ('dust you are and to dust you shall return'). YHWH 'destroys' (billa, swallows — the same verb used in v.8 for swallowing death itself) this universal death-covering.</p>",
    "8": "<p>'He will swallow up death forever. The Lord GOD will wipe away every tear from every face; the disgrace of his people he will remove from all the earth — for the LORD has spoken' — the pivotal resurrection-and-restoration verse. 'Billa hammavet lanetsach, he will swallow up death unto forever/victory.' Paul quotes this in 1 Cor 15:54: 'When the perishable has been clothed with the imperishable, and the mortal with immortality, then the saying that is written will come true: Death has been swallowed up in victory.' Rev 21:4 draws directly on v.8b: 'He will wipe every tear from their eyes. There will be no more death or mourning or crying or pain.' The 'disgrace' (cherpah, reproach/shame) removed from all the earth — the shame of Israel's defeat and exile permanently removed. The closing 'for YHWH has spoken' (ki YHWH diber) authenticates this seemingly impossible promise.</p>",
    "9": "<p>'In that day they will say: This is our God; we waited for him, and he has saved us. This is the LORD; we waited for him. Let us rejoice and be glad in his salvation' — the recognition-and-response formula of the saved community. 'Hineh elohenu zeh, behold, this is our God!' — the deictic (pointing) 'this is' of recognition at the moment of fulfillment. The double qivvinu (we waited/hoped): 'we waited for him and he will save us; we waited for him.' The waiting theology of the psalms (Ps 25:5; 27:14; 33:20; 37:7; 40:1; 130:5-6) fulfilled — the hope that sustained the community through judgment is now validated. 'Vegilah venismecha bishuato, and we will rejoice and be glad in his salvation' — the twin verbs of joy (gil = exult; samach = rejoice) expressing complete satisfaction.</p>",
    "10": "<p>'For the hand of the LORD will rest on this mountain, but Moab will be trampled in place, as straw is trampled down into a dung heap' — the contrast: Zion receives YHWH's resting hand; Moab receives trampling. 'Ki-tanuach yad YHWH bahar hazeh, for the hand of YHWH will rest on this mountain' (nuach = to rest/settle, the shabbat-rest vocabulary). The Moab contrast: Moab 'will be trampled in its place' (yedushshun, will be threshed/trampled) 'as straw is trampled in a dung-heap' (bemei madmenah, in the place of dung). The Moab oracle embedded here connects to the Moab oracles of chs. 15-16 and 16:5 (where the messianic throne is promised) — Moab's pride (16:6) is specifically addressed by the universal judgment while YHWH's mountain receives his blessing.</p>",
    "11": "<p>'He will spread his hands over Moab as a swimmer spreads his arms to stroke through water, and he will bring down their pride despite all their struggling' — the swimming imagery for YHWH's control of Moab: 'vefaras yadaiv beqirbo ka'asher yifros hashoheh lischot, he will spread his hands in the midst of it as a swimmer spreads out to swim.' The swimmer's arm-spreading controls the water — YHWH exercises the same control over Moab. 'Vehishpil ge'onotav im-arbbot yadaiv, he will bring low their pride with the craft of his hands' (im-arbbot yadaiv, with the trickery/cleverness of his hands = despite their struggling/scheming). The pride (ge'onotav) of Moab (16:6: 'Moab's arrogance — his immense pride') specifically targeted.</p>",
    "12": "<p>'The high fortifications of your walls he will pull down, lay low, and cast to the ground — to the very dust' — the complete demolition of Moab's defenses: 'umivsach migbeh chomotaiv, and the stronghold of the height of your walls' — the highest, most impregnable fortifications. 'Hishpil higbiah, he will bring low, make high ones low' (the classic reversal of high-and-low throughout Isaiah). 'Higgiya le'afar, he will bring it to the dust' — the same 'to the dust' as 25:5 (to the ground, to the very dust). Kir-haraseth (the great Moabite fortress city, modern Kerak) on its hilltop is the specific referent — its high walls pulled down to the dust.</p>"
  },
  "26": {
    "1": "<p>Isaiah 26:1 opens another hymn — the song of the redeemed community in the land of Judah. 'Bayom hahu yushhar hashir hazeh be'erets Yehudah, in that day this song will be sung in the land of Judah.' The song is explicitly placed 'in the land of Judah' (the restored covenant community's territory) and 'in that day' (the eschatological time of fulfillment). 'Ir az lanu, a strong city is ours' (az, the strength/power). 'Yeshuah yasit chomot uvayit, salvation he appoints as walls and ramparts' — YHWH's salvation is the city's actual defensive structure, not human engineering (contrast 22:8-11 where Judah looked to human arsenals and engineering). The contrast with the 'city of chaos' (24:10) is complete.</p>",
    "2": "<p>'Open the gates, so that the righteous nation that keeps faith may enter' — the Zion gate-opening: 'pitchu she'arim veyavo goi-tsaddiq, open the gates so that the righteous nation may enter.' The gates of the strong city are opened for the righteous (tsaddiq, just/righteous). 'Shomer emunim, keeper of faithfulness/truths' — the community defined by its faithful keeping (shomer = guardian/keeper; emunim = faithfulnesses/truths). The gate-opening for the righteous echoes Ps 118:20 ('this is the gate of the LORD through which the righteous may enter') and Rev 21:24-27 ('the nations will walk by its light, and the kings of the earth will bring their splendor into it; the gates will never be shut').</p>",
    "3": "<p>'You will keep in perfect peace the one whose mind is stayed on you, because he trusts in you' — the 'shalom shalom' verse: 'yetser samukh tishmar shalom shalom ki vekhah batuch, the mind/inclination leaning on you — you will keep in peace, peace, because in you he trusts.' The double shalom (peace-peace) = the completeness of peace, the fullness of covenant well-being. The 'mind' (yetser, the inclination/imagination — from yatsar = to form, the same root as YHWH forming Adam, Gen 2:7) 'leaning/propped against' (samukh, supported by) YHWH = the mind that makes YHWH its support/foundation. The trust (batach, the verb of calm reliance) is the ground of the peace. This verse is among the most quoted in Christian spirituality — the peace of God that passes understanding (Phil 4:7) rests on the same theology.</p>",
    "4": "<p>'Trust in the LORD forever, for the LORD — Yah himself — is an everlasting Rock' — 'bitchu vaYHWH adei-ad, trust in YHWH unto forever.' The command to trust not circumstantially but permanently (adei-ad, unto eternity). 'Ki bYah YHWH tsur olamim, for in Yah YHWH is the Rock of eternities.' The divine title Yah (the shortened form of YHWH, used especially in doxological contexts — Hallelujah = praise Yah) combined with YHWH as double emphasis. The 'Rock of eternities' (tsur olamim) draws on Deut 32:4 ('the Rock, his work is perfect') and the Psalms' Rock-theology (Ps 18:2; 28:1; 31:3; 62:2). The everlasting Rock contrasts with the city of chaos (24:10) and Moab's high walls (25:12) that fall.</p>",
    "5": "<p>'For he brings down those who dwell on high; the lofty city he brings to the ground — to the very dust' — the consistent Day-of-the-LORD anti-pride theme: 'ki hishach yoshevei marom, for he brings low the inhabitants of the heights.' The 'lofty city' (qiryah nisha, the exalted city) brought 'to the very dust' (ad-afar yagienah, to the dust he makes it reach). The 'heights' (marom) that humans build for security and status are exactly what YHWH's judgment targets (2:11-17: 'the high and lofty brought low'). This connects to the Assyrian march narrative (10:28-32: the enemy approaching from the high places) and the 'city of chaos' (24:10).</p>",
    "6": "<p>'It will be trampled underfoot — by the feet of the poor, by the steps of the needy' — the reversal of the social order: the fallen lofty city is trampled 'by the feet of the poor' (beragel rash, by the foot of the poor man) and 'by the steps of the needy' (bif'amei dallim, by the steps/walking of the lowly). The same the poor who were oppressed by the lofty city now walk over its ruins. This specific reversal — the poor trampling the ruins of the proud city — echoes the Magnificat (Luke 1:52-53: 'He has brought down rulers from their thrones but has lifted up the humble') and the Beatitudes (Matt 5:3: 'Blessed are the poor in spirit, for theirs is the kingdom of heaven').</p>",
    "7": "<p>'The path of the righteous is level; you who are just make the way of the righteous smooth' — the moral topography of the redeemed order: 'orach letsaddiq meysharim, the path of the righteous is level/straight' (meysharim = uprightness/levelness, from yashar = straight/right). 'Yosher tphalles ma'gal tsaddiq, O upright One, you make smooth/level the path of the righteous.' The 'level path' contrasts with the treacherous terrain of judgment (17:12-14: the roaring nations that suddenly vanish). The road-smoothing for YHWH's approach (40:3-5: 'every mountain and hill made low; the rough ground shall become level') now applied to the righteous community's walk.</p>",
    "8": "<p>'In the path of your judgments, LORD, we have waited for you; your name and your renown are the deepest longing of our souls' — the waiting theology: 'af orach mishpatekhah YHWH qivvinukha, also in the path of your judgments YHWH we have waited for you.' Even in the path of divine judgments (the difficult road of history where YHWH's justice operates) the community waits (qivvah, the technical term for patient expectation). 'Your name and your renown' (shimkha ulezikhrkhah, your name and your memorial/remembrance) 'are the deepest longing of our souls' (tav'at nafesh, the desire/longing of our soul) — the soul's fundamental orientation toward YHWH's revealed character.</p>",
    "9": "<p>'My soul yearns for you in the night; within me my spirit seeks you eagerly; for when your judgments come upon the earth, the world's inhabitants learn what is right' — the night-yearning: 'nafshi ivvitikhah ballailah, my soul yearns for you in the night' — the darkness of waiting and suffering as the context for the soul's longing. 'Af-ruchi veqirbi ashcharekha, also my spirit within me seeks you at dawn/eagerly.' The night/dawn contrast: waiting through the night, seeking at dawn. 'When your judgments come upon the earth, the world's inhabitants learn righteousness' (learn tsedeq = learn what is right) — the didactic function of divine judgment: human beings learn righteousness through experiencing divine justice. This is the theological purpose of the Isaiah Apocalypse's judgment: not destruction for its own sake but the world learning what is right.</p>",
    "10": "<p>'Even when the wicked receive grace, they do not learn righteousness; in a land of uprightness they act wrongly and fail to see the LORD's majesty' — the perversity of the wicked response to grace: 'yuchan rasha belo lamad tsedeq, even if the wicked are shown grace, he does not learn righteousness.' Divine grace does not automatically produce learning in the morally unformed. 'Be'erets nesharot ye'awel, in a land of uprightness/rectitude he acts perversely.' Even in a righteous environment, the wicked person continues in wickedness. 'Velo yireh geat YHWH, and he will not see the majesty of YHWH' — the fundamental problem: the wicked literally cannot perceive divine majesty. The connection to Isa 6:9-10 (hearing but not understanding, seeing but not perceiving) is the same diagnostic of hardened spiritual insensibility.</p>",
    "11": "<p>'LORD, your hand is raised high, but they do not see it. Let them see your zeal for your people and be put to shame. Let the fire reserved for your enemies consume them' — the prayer that judgment would produce the necessary sight: 'YHWH ramah yadkha bal-yechezu, YHWH, your hand is raised high but they do not see.' The raised divine hand of judgment (the same outstretched hand of 9:12-10:4) invisible to those who are spiritually blind. The petition: 'let them see your zeal for your people' (yechezu qin'at-ammekha veyevashu, let them see your jealousy/zeal for your people and be put to shame). YHWH's covenantal jealousy (qin'ah, the burning devotion that protects Israel) becomes visible in judgment. 'Fire reserved for your enemies' (esh tsarekha tokhelm, fire of your adversaries will consume them) = the eschatological fire of divine judgment.</p>",
    "12": "<p>'LORD, you will establish peace for us; for all we have accomplished, you have done it for us' — the theological reversal of all human accomplishment: 'YHWH tishpat shalom lanu, YHWH you will establish peace for us.' All Israel's achievements (kol-ma'asenu, all our works) are attributed to YHWH's doing (ki gam kol-ma'asenu paaleta lanu, for even all our works you have worked for them). The 'all our works, you have done for us' is the anti-Boasting statement: any human accomplishment within YHWH's economy is ultimately his gift. This is the theology of Eph 2:10 ('we are God's handiwork, created in Christ Jesus to do good works, which God prepared in advance for us to do') — the good works are simultaneously ours and YHWH's.</p>",
    "13": "<p>'LORD our God, other masters have ruled over us; but we will acknowledge your name alone' — the historical acknowledgment of foreign domination: 'YHWH Elohenu bealunu adonim zulatekhah, YHWH our God, other lords besides you have ruled over us.' The 'other lords' = Assyrian, Babylonian, and other imperial overlords who claimed sovereignty over Israel. 'Raq bekha nazkir shemekha, only in you will we remember/invoke your name' — the covenant exclusivity after the experience of foreign dominion. The 'only' (raq) is emphatic: after experiencing what other masters bring, the restored community turns exclusively to YHWH's name. The naming-and-invoking of YHWH's name is the primary worship act of the covenant community (Gen 4:26; 12:8; 1 Kgs 18:24).</p>",
    "14": "<p>'They are dead — they will not live again; the shades below will not rise. You have punished them and destroyed them, and wiped out every memory of them' — the finality of the oppressors' death: 'metim bilthi-yichyu refaim bilthi-yaqumu, the dead will not live, the shades will not rise' — the false masters are permanently dead. The emphatic negation (bilthi, emphatically not) contrasts with v.19's 'your dead will live.' The oppressors (foreign rulers) face permanent death while YHWH's people (v.19) face resurrection. 'Wiped out every memory of them' (vatashmed vetabed kol-zeker lamoh, you have destroyed and wiped out every memory of them) — the opposite of covenant memorial (zeker = memory/memorial). The oppressor's name and memory erased is their complete destruction.</p>",
    "15": "<p>'You have enlarged the nation, LORD; you have enlarged the nation and gained glory; you have extended all the borders of the land' — the covenant blessing of territorial expansion: 'yisapta lagoi YHWH yisapta lagoi, you have enlarged the nation, YHWH, you have enlarged the nation' — the doubled verb emphasizing divine initiative in the nation's growth. 'You have gained glory' (nikbadta, you are honored/glorified). 'Richakata kol-kinkei erets, you have extended all the borders of the land' — the Abrahamic promise of land (Gen 15:18: 'from the Wadi of Egypt to the great river, the Euphrates') extended to its fullest scope. The paradox of the Isaiah Apocalypse: universal judgment (24:1-23) and universal restoration (25:6-26:15) are both YHWH's work.</p>",
    "16": "<p>'LORD, in their distress they sought you out; when your discipline fell on them, they whispered their prayers to you' — the prayer-in-distress pattern: 'YHWH batsar paqadukhah, LORD in distress they visited/sought you.' The tsarah (distress/trouble) as the catalyst for prayer. 'Tsaqun lachash mussarkhah lamoh, they poured out a whispered prayer when your discipline was on them' — 'whispered prayer' (lachash = a whisper, a charm, a quiet prayer vs. loud public prayer) during 'your discipline' (musar, the corrective discipline of the father-son covenant). Prov 3:11-12: 'do not despise the LORD's discipline... because the LORD disciplines those he loves.' The discipline that produces the whispered prayer of repentance is the purposeful parenting of the covenant God.</p>",
    "17": "<p>'As a pregnant woman near delivery writhes in pain and cries out in her anguish, so have we been in your sight, LORD' — the labor-pain image for the community's distress: 'ka'asher tihryeh tiqrav laledah techil, as a pregnant woman when she approaches birth writhes in labor.' The labor pains of the covenant community: 'ken hayinu mipanekha YHWH, so we have been before your face, O LORD.' The community identifies itself as the laboring woman about to give birth. But the delivery fails (v.18) — they labor without producing salvation, only 'wind' (ruach). The labor-pain imagery appears throughout the prophets for both the people's distress and YHWH's creative activity.</p>",
    "18": "<p>'We were pregnant, we writhed in labor, but we gave birth to nothing but wind. We have brought no deliverance to the earth, and the world's oppressors have not been overthrown' — the failed birth: 'harinu chalnu, we were pregnant, we writhed in labor' — repeating the labor-pain imagery of v.17. 'Ke'ilu-yaldnu ruach, as it were we gave birth to wind' — ruach (wind/spirit = nothing substantial). 'Yeshuot lo-naaseh erets, we have not worked salvation for the earth; vebal-yippelu yoshevei tevel, and the world's inhabitants have not fallen.' Human effort (even when animated by genuine distress and prayer) cannot produce the salvation YHWH alone can give. The community's self-assessment prepares for the divine promise of v.19: what human labor cannot produce, YHWH gives freely.</p>",
    "19": "<p>'Your dead will live; my corpse will rise. Awake and sing for joy, you who lie in the dust! For your dew is like the morning dew on fresh grass, and the earth will give birth to its dead' — one of the OT's clearest resurrection promises. 'Yicheyu metekha, your dead will live; nevali yequmun, my body/corpse will rise.' The first-person shift (from 'your dead' to 'my corpse') may be the prophet speaking for himself or for the community. 'Haqitzu veranenu shokhnei afar, awake and shout for joy, dwellers in the dust!' — the resurrection command directed to those who 'dwell in dust' (death, Job 21:26; Ps 22:29). 'Ki tal oroth tallekha veharets refaim tapil, for your dew is the dew of lights/luminaries, and the earth will cast down the shades' (or: give birth to the shades). The morning dew as the life-giving agent of resurrection: in the dry Near East, dew was the primary moisture during the dry season, sustaining plant life — here YHWH's dew brings the dead to life. Dan 12:2 develops this further.</p>",
    "20": "<p>'Come, my people, enter your chambers and shut your doors behind you. Hide yourself for just a little while until the LORD's wrath has swept past' — the Passover echoes: 'lekh ami bo vechadarekhah, go my people, enter your chambers.' The hiding instruction echoes Exod 12:22-23 (Passover night: 'none of you shall go out the door until morning... when YHWH passes through to strike down the Egyptians'). 'Sigru delatekhakha baadekhah, shut your doors behind you' — the protection of the interior space during the divine wrath. 'Chavi kim'at-rega ad-yaavor za'am, hide for a short time until the wrath passes over.' The 'passes over' (yaavor = passes over, same root as Passover/Pesach = passing over) is almost certainly a deliberate allusion. The divine wrath 'passes over' those who are sheltered, as in Egypt.</p>",
    "21": "<p>'For look — the LORD is coming out of his place to punish the earth's inhabitants for their sin. The earth will expose its blood and no longer cover its slain' — the divine warrior's departure: 'ki hineh YHWH yotsem mimekomo, for behold YHWH is going out from his place to punish the inhabitants of the earth.' YHWH 'leaving his place' (mimekomo) is the theophanic departure from the heavenly sanctuary for judgment — Mic 1:3 ('the LORD is coming from his dwelling place; he comes down and treads on the heights of the earth'). 'The earth will expose its blood' (vegiltah ha'arets et-dameiha, and the earth will uncover her blood) 'and no longer cover its slain' (velo tekhasse od al-harageiha, and will no longer cover over her slain). The ground that 'covered' murder (Gen 4:10: 'your brother's blood cries out to me from the ground') will be unable to hide it any longer at the final judgment.</p>"
  },
  "27": {
    "1": "<p>Isaiah 27:1 applies the ANE cosmic combat mythology to YHWH's eschatological victory: 'bayom hahu yifqod YHWH becherbo haqqasheh vehagedolah vehachazaqah, in that day YHWH will visit with his sword, the hard and the great and the strong one.' The three-fold description of the sword (hard = qasheh; great = gadol; strong = chazaq) emphasizes its irresistibility. 'Al-livyatan nachash bariach ve'al-livyatan nachash aqalaton veharag et-hatannin asher bayam, against Leviathan the fleeing serpent and against Leviathan the coiling serpent; and he will slay the dragon in the sea.' Leviathan (livyatan) appears in the Ugaritic Baal Cycle as Lotan (lt-n) — Baal's great sea-enemy with seven heads — whom Baal defeats. The two Leviathans ('fleeing/runaway' and 'twisted/coiling') are the two epithets of the Ugaritic Lotan. YHWH here claims the cosmic dragon-combat for himself. Rev 12:9 identifies the dragon as the ancient serpent/Satan.</p>",
    "2": "<p>'In that day, sing about it: A vineyard of choice wine!' — the second vineyard song (cf. 5:1-7, the first). The contrast is complete: the first vineyard produced bad fruit and was destroyed (5:2-7); this vineyard is 'of choice wine' (chemd, desire/delight). 'Bayom hahu kerem chemd anu lah, in that day, a vineyard of choice wine — sing about it!' The singing command is joyful: the damaged vineyard of ch.5 is now the delightful vineyard of ch.27. The vine (Israel) that had been devastated by judgment is now restored and productive. The joy of the new vineyard song is the response to Leviathan's defeat (v.1) — when the chaos-monster is slain, the vineyard flourishes.</p>",
    "3": "<p>'I, the LORD, tend it; I water it constantly; so that nothing can hurt it, I guard it day and night' — YHWH as the perfect vinedresser: 'ani YHWH notzerah liraga'im ashqennah, I the LORD keep it; moment by moment I water it.' The 'moment by moment' watering (liraga'im, at every moment) emphasizes constant divine care. 'Pen yifqod aleihah lailah veyomam entsurennah, lest anything visit it — night and day I guard it.' The all-day-all-night guardianship contrasts with the first vineyard's guardian who went away (5:2: 'then he went away'). The theme of YHWH as the shepherd-guardian who does not sleep (Ps 121:3-4: 'He who watches over Israel will neither slumber nor sleep') applied to the vineyard-watching.</p>",
    "4": "<p>'I have no wrath against my vineyard. If briers and thorns came against me in battle, I would stride through them and burn them all down' — the absence of wrath: 'chemah ein li, I have no wrath' (chemah = the hot anger of divine jealousy, the burning passion). The briers and thorns (shamir vashayit — the judgment-vegetation of 5:6; 7:23-25; 9:18; 10:17) now come not from YHWH against the vineyard but from enemies against the vineyard's keeper. YHWH's response: 'eflasah bah achadah ashitenah yachdav, I would stride through it as a unit, I would burn them together.' The vineyard's enemies are burned rather than the vineyard itself being burned (as in 5:6: 'I will make it a wasteland... no rain').</p>",
    "5": "<p>'Or else let him come to me for refuge; let him make peace with me — yes, let him make peace with me' — the alternative to burning: the open invitation to peace. 'O yachazek bema'uzi yaaseh shalom li, or let him grasp my refuge/stronghold, let him make peace with me.' The double 'let him make peace with me' (shalom yaseh-li shalom yaseh-li) is an emphatic invitation: even the briers and thorns (enemies) can choose peace over burning. This is the paradox of divine wrath alongside divine invitation: the same God who burns his enemies invites them to come for refuge. The 'grasping the stronghold' = the faith-act of running to YHWH for protection rather than fighting against him.</p>",
    "6": "<p>'In coming days Jacob will take root; Israel will blossom and sprout and fill the whole world with fruit' — the eschatological fruitfulness of the restored vineyard: 'habba'im yashresh Ya'aqov, in coming days Jacob will take root.' The metaphor develops: ya'aqov yashresh = Jacob takes root (the deep underground work of establishing the plant); yatsis ufarak Yisrael = Israel blossoms and flowers; umile'u venei tevel tenuvah = and they fill the face of the world with fruit. The three stages (root, blossom, fruit-filling) describe the progressive eschatological fruitfulness. 'Fill the world with fruit' = the Abrahamic multiplication blessing (Gen 1:28; 12:3; 22:17-18) realized through Israel as the fruit-bearing vine. John 15:5 applies this vineyard fruitfulness to the disciples united to Christ.</p>",
    "7": "<p>'Has God struck Israel as he struck those who attacked Israel? Has Israel been killed as she killed her enemies?' — the comparative-proportionality question: 'hekimakkath-makkehv hikahv, is his striking like the striking of his striker?' The question probes the proportionality of Israel's judgment versus the judgment of her enemies. The implied answer: No — Israel's judgment was measured/proportionate (v.8: 'by measure he dealt with her') while the enemies were completely destroyed. The differentiated judgment reflects the covenant relationship: Israel, as YHWH's own, receives corrective discipline (musar = parental correction); the enemies receive destruction. Amos 3:2: 'You only have I chosen of all the families of the earth; therefore I will punish you for all your iniquities.'</p>",
    "8": "<p>'By measured exile he dealt with Israel; he removed her with his fierce wind — the scorching east wind' — the 'measured exile' of Israel: 'besa'assah beshale'ah terivennah, by measure, by driving out, you contend/quarrel with her.' The disciplinary exile is measured — not total annihilation (as with Assyria or Babylon) but a carefully proportioned removal. 'Hagas beruchot kashshah beyom qadim, he expelled her with his fierce wind, on the day of the east wind.' The east wind (qadim) is the sirocco that blows off the desert — hot, dry, destructive (Jon 4:8; Job 27:21; Jer 18:17). The exile as a divine wind-blast: forceful but controlled.</p>",
    "9": "<p>'By this, then, Jacob's guilt will be atoned for; this is the full result of the removal of his sin: he will crush the altar stones to chalk, and no Asherah pole or incense altar will stand' — the exile as the instrument of atonement: 'lakhen beze yechupar avon Ya'aqov, therefore by this Jacob's guilt will be atoned' (yechupar from kaper = to cover/atone). The exile accomplishes what centuries of voluntary repentance had not: the removal of idolatry. 'He will crush all the altar stones like chalk' (vesam kol-avnei mizbeach ke'avnei-gir menupatsot, he will make all the altar stones like chalk stones crushed). The Asherah poles (asherim) and incense altars (chammanim) removed — the objects that constituted Israelite apostasy (2 Kgs 23:4-15: Josiah's reform destroyed exactly these objects, partially fulfilling the oracle).</p>",
    "10": "<p>'The fortified city stands deserted, its dwellings abandoned like a wilderness — there calves graze and lie down, stripping its branches bare' — the desolate city as a sign of completed judgment: 'ki ir betsura badad mivshar meshulach veneerav, for the fortified city is deserted, a lonely dwelling, abandoned like a wilderness.' The domestic animals inhabiting the ruins: 'sham yireh egel vesham yirbets vekilah seifoteiyha, there calves will graze and there lie down and consume its branches.' The calves consuming the city's vegetation = the complete takeover of human space by agricultural use (the city reverting to farmland). This image appears throughout the judgment oracles (13:20-22; 17:2; 34:13-15).</p>",
    "11": "<p>'When its branches wither, they are broken off; women come and make fires with them. For this is a people without understanding, so their Maker will not have compassion on them, and their Creator will show them no mercy' — the final judgment on the people 'without understanding': 'bifshel qetzira teissaber nashim bao me'irot otah, when its branch is dry it is broken; women come, making fire with it.' The dried branch used as firewood = the utterly useless remnant of the apostate city. The diagnosis: 'ki lo am beinot hu, for this is a people without understanding.' The lack of understanding (beinot = discernment/insight) is the fundamental prophetic diagnosis of Israel's failure (Isa 1:3: 'Israel does not understand'). 'Al-ken lo yerachemannu osehv, therefore his Maker will not have compassion on him; veyotsero lo yechunnenu, and his Creator will show him no mercy.'</p>",
    "12": "<p>'In that day the LORD will thresh out his grain from the Euphrates to the Brook of Egypt, and you will be gathered up one by one, O people of Israel' — the eschatological ingathering as threshing: 'vehayah bayom hahu yachbot YHWH mishipbolet hannahar, in that day YHWH will thresh from the flowing of the River' (hannahar = the Euphrates, the great river of Mesopotamia). 'Ad-nachal Mitsrayim, to the brook of Egypt' (the Wadi el-Arish, the traditional southwestern boundary of the land). The entire territory from the northeast boundary (Euphrates) to the southwest boundary (Brook of Egypt) = the full Promised Land extent (Gen 15:18). 'And you will be gathered one by one, O people of Israel' (velaqutem lachat echad benei Yisrael, and you will be gathered, one by one, O children of Israel) — the careful, individual gathering contrasts with the mass deportations of exile.</p>",
    "13": "<p>'In that day a great trumpet will sound, and those who were perishing in the land of Assyria and those exiled in Egypt will come and worship the LORD on the holy mountain at Jerusalem' — the great trumpet of ingathering: 'vehayah bayom hahu yittaqa beshofar gadol, in that day a great shofar will be blown.' The shofar gadol (great ram's horn) is the signal of the eschatological gathering (Matt 24:31: 'he will send his angels with a great trumpet call'; 1 Thess 4:16: 'with the trumpet call of God'; 1 Cor 15:52: 'the last trumpet will sound'). Those 'perishing in Assyria' and 'exiled in Egypt' = the northern exiles (722 BCE deportation to Assyria) and those who fled to Egypt. 'They will worship the LORD on the holy mountain at Jerusalem' — the eschatological worship on Zion fulfills the pilgrimage theology of Isa 2:2-4.</p>"
  },
  "28": {
    "1": "<p>Isaiah 28:1 begins the third major woe-section (chs. 28-33) with the woe against Ephraim. 'Hoi ateret ga'ut shikkurei Efraim, woe to the proud crown of Ephraim's drunkards.' The 'proud crown' (ateret ga'ut, crown of pride) = Samaria, built on a hill in the fertile valley of the northern Kingdom — visible from a great distance, a commanding position. 'Whose glorious beauty is a fading flower' (tsits nevel tiferet tsiveo, a fading blossom, his glorious beauty) — the beautiful blossom that fades quickly. 'Al-rosh gei-shemanim, on the head of the valley of fat things' (gei-shemanim = the fertile valley, perhaps the Jezreel valley or the valley around Samaria). 'Haloumim yayin, struck down by wine' = the political/military elite overcome by their own pleasure. 722 BCE: the Assyrian siege and fall of Samaria is the fulfillment.</p>",
    "2": "<p>'See, the Lord has a powerful agent — like a devastating hailstorm, like a destructive tempest, like a flood of overwhelming waters — who will smash it to the ground' — Assyria as YHWH's instrument: 'hineh chazaq ve'ammitz laAdonay, behold one who is mighty and strong for the Lord.' The three weather images for Assyrian military power: (1) ze'rem barad, a devastating hailstorm — hail that destroys crops; (2) sa'ar qataev, a destructive storm; (3) ze'rem mayim kabirim shotfim, a flood of overwhelming rushing waters — the same 'overwhelming flood' imagery as 8:7-8 (the Assyrian river overflowing). 'Hieniach la'aretz beyad, he will put it down to the earth by force' — Samaria smashed to the ground by the overwhelming agent.</p>",
    "3": "<p>'The proud crown of Ephraim's drunkards will be trampled underfoot' — the trampling of the proud crown: 'beraglaim titbosas ateret ga'ut shikkurei Efraim, by feet it will be trampled — the proud crown of Ephraim's drunkards.' The 'pride' crown literally trampled underfoot by the Assyrian military (who marched through Israel). The reversal of the crown-as-symbol: what is worn on the head (the highest point) is thrown to the ground and trampled (the lowest). The same reversal as 25:12 (Moab's high walls brought to the dust) and 26:5-6 (the lofty city trampled by the poor).</p>",
    "4": "<p>'The beautiful crown on the head of the fertile valley will be a fading flower, like a first-ripe fig before summer: whoever spots it snatches and swallows it on the spot' — the eagerness of the conqueror: 'vehayeta tiferet navlato asher al-rosh gei-shmanim kebikkurah bilah, the fading flower of his beauty that is on the head of the fat valley will be like the early fig before summer.' The bikkurah (early fig) ripens before the main crop and is immediately eaten by whoever spots it. 'Asher yireh haro'eh othah beoddah vekappo yivalteenah, which whoever sees picks it while it is still in his hand and swallows it' — immediate consumption. Samaria's wealth attracted the Assyrian conqueror who 'swallowed' it immediately. The early-fig imagery = premature destruction before the full harvest of the kingdom's potential.</p>",
    "5": "<p>'In that day the LORD of hosts will be a glorious crown and a beautiful diadem for the remnant of his people' — the positive vision for the remnant: 'bayom hahu yihyeh YHWH tseva'ot la'ateret tiferet ulitstil tiferet, in that day YHWH of hosts will be a crown of glory and a diadem of beauty.' YHWH himself replaces the proud crown of Ephraim (v.1) — not a crown worn by humans but YHWH as the crown worn by his people. 'For the remnant of his people' (lishe'ar ammo) — the remnant theology: those who survive judgment receive YHWH himself as their glory-crown. The contrast: Ephraim's crown was fading (v.1, 4); YHWH as crown is eternal glory.</p>",
    "6": "<p>'And he will be a spirit of justice for those who sit in judgment, and strength for those who repel the battle at the gate' — the practical governance of the messianic era: 'ulruach mishpat layoshev al-hammishpat, and a spirit of justice to those who sit in judgment.' The spirit of justice (ruach mishpat = the judicial Spirit of God empowering the judges — the same sevenfold Spirit of 11:2: 'Spirit of counsel and strength, Spirit of knowledge and fear of YHWH') enabling right judgment. 'Uligevurah mshivei milchamah sha'arah, and strength to those who push back the battle at the gate.' The gate-defenders (those who repel the military threat at the city gate) empowered by divine strength. The two functions: just governance and effective defense.</p>",
    "7": "<p>'But these too stumble through wine and stagger from strong drink: priest and prophet are overcome by strong drink, confused by wine, reeling from intoxication — they err in their visions and stumble in their judgments' — the indictment of Jerusalem's religious leadership. 'Vegam-eleh bayayin shagu, but also these err because of wine' — the 'also these' (gam-eleh) connects the Jerusalem leadership to the drunken Ephraimites of vv.1-4: the same problem south as north. Priests (kohen) and prophets (navi) both overcome (balu, swallowed/overwhelmed) by wine and strong drink. 'Tagu baro'eh paqeku mispat, they err in the vision/seeing and stumble in judgment' — the prophets' visions (ro'eh = seer) and the priests' legal judgments (mishpat) both compromised by drunkenness. The religious establishment that should provide the correction for Ephraim's pride is equally corrupt.</p>",
    "8": "<p>'All the tables are covered with vomit and filth; there is no clean space anywhere' — the physical evidence of the drunken leadership: 'ki kol-shulchanot male'u qi tso'ah, for all the tables are full of vomit/vomited material and filth, bli-maqom, no place (is clean).' The sacred table of the covenant meal (Exod 24:11: Moses and the elders ate before YHWH; the Bread of the Presence on the table in the tabernacle) is now covered in vomit. The sacred/profane reversal is complete: what should be the place of divine communion is the site of defilement. The physical description is viscerally disgusting by design — the shock value conveys the moral seriousness of the leadership's failure.</p>",
    "9": "<p>'Who is he trying to teach? Who is he trying to make understand his message? Babies just weaned from milk, infants just taken from the breast?' — the mocking dismissal of the prophet by the corrupt leadership: 'et-mi yore dea, whom is he (the prophet/YHWH) teaching knowledge?' The 'who' is dismissive — the drunk priests and prophets mock the prophetic instruction as baby-talk. 'Ve'et-mi yavin shemu'ah, and who is he making to understand what he hears?' 'Gamelei mechalav atiqei mishadayim, those just weaned from milk, those just taken from breasts?' — the mockers compare the prophet's listeners to weaned infants, implying the prophetic message is too elementary for sophisticated adults. But the mockery backfires (v.13): the 'baby-talk' they dismiss will become the incomprehensible Assyrian speech that judges them.</p>",
    "10": "<p>'For it is rule on rule, rule on rule; line on line, line on line; a little here, a little there' — the 'tsav latsav' verse: 'ki tsav latsav tsav latsav, qav laqav qav laqav, ze'er sham ze'er sham.' This is either (1) a mockery of Isaiah's teaching as repetitive babble (the leaders imitating what they perceive as Isaiah's boring elementary instruction), or (2) Isaiah quoting the drunken prophets' own slurred speech, or (3) Hebrew transliteration of what Assyrian speech sounds like to Israelite ears. All three interpretations converge: the mocking of prophetic instruction will be answered by foreign speech (v.11). The onomatopoetic quality — tsav tsav, qav qav — mimics the sound of incomprehensible or mocking speech.</p>",
    "11": "<p>'For by people of strange lips and a foreign tongue the LORD will speak to this people' — the judgment-through-foreign-speech oracle: 'ki bela'aze safah uvelashon acheretm yedabber el-ha'am hazeh, for through stammerers of lip and through a different tongue he will speak to this people.' The people who mocked prophetic instruction as baby-talk will be spoken to in an actual foreign language (Assyrian) they cannot understand. Paul quotes v.11-12 in 1 Cor 14:21-22 to discuss speaking in tongues: 'Through people of strange tongues and through the lips of foreigners I will speak to this people, but even then they will not listen to me, says the Lord. Tongues, then, are a sign, not for believers but for unbelievers.' The tongue-as-judgment for unbelief becomes the tongue-as-sign in the NT context.</p>",
    "12": "<p>'He said to them: This is the place of rest; give rest to the weary; this is the refreshing. But they refused to listen' — the rejected invitation: 'asher amar alehem, who said to them: zot hamenuchah, this is the rest.' YHWH had offered rest (menuchah = the deep Sabbath-rest of covenant security) to the 'weary' (yeaef, the exhausted/wearied = the covenant community burdened by Assyrian pressure). 'Vezot hamargea'ah, and this is the refreshment' (margeah = rest, relief). 'Velo avu shimoa, but they refused to hear.' The refusal of divine rest echoes the Wilderness generation's failure to enter the rest (Ps 95:11: 'they shall never enter my rest'; Heb 3:11; 4:1-10: the Sabbath-rest that remains for the people of God).</p>",
    "13": "<p>'So the word of the LORD will become to them: rule on rule, rule on rule; line on line, line on line; a little here, a little there — so that they stumble backward, are broken, snared, and captured' — the word becomes judgment: 'vehayah lahem davar YHWH, and the word of YHWH will become to them: tsav latsav...' The same 'tsav latsav' mocking formula of v.10 returns — but now it is YHWH's word becoming to them the very incomprehensibility they mocked. The outcome: 'lema'an yelechu venichshelu achor venishberu venoqushu venilkadu, so that they stumble backward, are broken, snared, and captured.' The four verbs of progressive disaster: stumble → break → snare → capture = total judgment. The word they mocked becomes the instrument of their destruction.</p>",
    "14": "<p>'So hear the word of the LORD, you scoffers who rule this people in Jerusalem' — the direct address to the Jerusalem ruling class: 'lakhen shime'u debar YHWH anshei latson, therefore hear the word of YHWH, O men of scoffing.' The latson (scoffing/mocking) is the specific sin of vv.9-10 — those who mockingly dismissed prophetic instruction as baby-talk. 'Moshle ha'am hazeh asher biYerushalayim, those who rule this people in Jerusalem.' The ruling class (judges, counselors, senior officials) who have the responsibility of governing Jerusalem are specifically addressed. Their scoffing is not merely impolite — it is the political decision-maker's rejection of prophetic counsel, which will prove catastrophic.</p>",
    "15": "<p>'You have said: We have made a covenant with death; with Sheol we have an agreement. When the overwhelming flood sweeps through, it will not touch us — for we have made lies our shelter and hidden ourselves under falsehood' — the 'covenant with death': 'karam berit et-mavet, for you have said: we have cut a covenant with death.' The diplomatic language (karat berit = to cut a covenant, the standard treaty formula) applied to a supposed alliance with death itself. The 'agreement with Sheol' (chozeh im-she'ol, a vision/pact with Sheol) = the belief that they have arranged exemption from judgment. The 'overwhelming flood' (shetef, the sweeping/overflowing flood = Assyrian conquest) 'will not reach us' (ki im-yaavor lo yevoinenu, for when it passes it will not come to us). Their protection: 'samnu chazav machsenu, we have made a lie our refuge; uvasheker nistarenu, and in falsehood we have hidden.' Their diplomatic arrangements (Egyptian alliance? political maneuvering?) built on falsehood.</p>",
    "16": "<p>'So this is what the Lord GOD says: See, I am laying a stone in Zion — a tested stone, a precious cornerstone, a sure foundation. Whoever believes will not make haste' — the cornerstone oracle, the most NT-quoted verse in Isaiah's foundation section. 'Hineni yissad beTziyon even even bochan pinnat yiqrat muyyasar, behold I lay in Zion a stone, a stone of testing, a precious cornerstone, a sure foundation.' The four attributes: bochan (tested), yiqrat (precious/valued), pinnat (corner), muyyasar (sure/established foundation). 'Hama'amin lo yachish, he who believes/trusts will not make haste/panic' (lo yachish = will not flee in panic, will not be in anxious haste). Quoted in Rom 9:33 and 10:11 (Paul adds 'will not be put to shame' from Ps 118:22); 1 Pet 2:6-8 (combined with Ps 118:22 and Isa 8:14). The Qumran community (1QS 8.7-8) applied this to the community itself as the living cornerstone.</p>",
    "17": "<p>'I will measure with justice as my plumb line and righteousness as my level. The hail will sweep away your refuge of lies, and the flood will overwhelm your hiding place' — the divine building-inspection using justice and righteousness: 'vesamti mishpat leqav utsedaqah lemishqelet, and I will make justice the measuring line and righteousness the plumb line.' The measuring line (qav) and plumb line (mishqelet) are the builder's tools for checking whether a structure is true and straight — if justice and righteousness are the standard, the 'covenant with death' fails the inspection. 'Ubarad yikchah machaseh-chazav, and hail will sweep away the refuge of lies.' The hail (barad, the hail that destroys crops = divine judgment) 'sweeps away' the lie-refuge. 'Vemayim yishtofu miseter, and water will overwhelm the hiding place' — the flood they claimed would not touch them does.</p>",
    "18": "<p>'Your covenant with death will be cancelled, and your agreement with Sheol will not hold. When the overwhelming flood sweeps through, you will be crushed under it' — the nullification of the death-covenant: 'vekuppar britekhemm et-mavet, your covenant with death will be annulled/wiped out' (kappar = to wipe out/atone = the atonement-removal vocabulary applied to the annulment of their illusory covenant). 'Vehazutekhemm et-she'ol lo taquom, and your vision/pact with Sheol will not stand.' The Assyrian 'overwhelming flood' they thought would bypass them: 'veam-yaavor shetef vehiyitem lo lemirmas, and when the sweeping flood passes, you will become trampled by it.' The very flood they made a covenant to avoid becomes what tramples them.</p>",
    "19": "<p>'Every time it sweeps through, it will seize you. Morning after morning it will come — by day and by night. The very understanding of what it means will be terror' — the relentless repetition of judgment: 'mideiy avoro yiqqach etkhem, as often as it passes it will take/seize you.' The frequency: 'boqer boqer ya'abor bayom uvalayelah, morning by morning it will pass, by day and by night.' The unceasing morning-by-morning quality of the judgment — no rest between waves. 'Vehayah raq ziggavon havin shemu'ah, and it will be nothing but sheer terror to understand the report/message.' The 'understanding' (havin, discerning) of what is happening produces only terror (ziggavon = trembling). The moment of comprehension is the moment of terror — they finally understand what was prophesied but too late to respond.</p>",
    "20": "<p>'The bed will be too short to stretch out on, and the covering too narrow to wrap yourself in' — the proverb of inadequate comfort: 'ki-qatsar hammatsea mehishtaream, for the bed is too short to stretch out on' (qatsar = too short). 'Vehammasekha tsarah lehitkannef, and the covering is too narrow to wrap yourself in.' The inadequate bed and narrow blanket are a vivid image of the futility of the 'covenant with death' — the arrangements they made to protect themselves are like trying to sleep on a too-short bed with a too-narrow blanket. There is no comfortable security in the false covenant. The proverb-like quality suggests an existing saying that Isaiah applies to the political situation.</p>",
    "21": "<p>'For the LORD will rise up as he did at Mount Perazim; he will be roused as in the valley of Gibeon, to carry out his task — his strange task — his work — his alien work' — the two historical YHWH-warrior victories invoked: 'ki keBEhar Peratsim yaqum YHWH, for as on Mount Perazim YHWH will rise up.' Mount Perazim = Baal-Perazim (2 Sam 5:20: 'YHWH broke through my enemies before me like a bursting flood' — David's victory over the Philistines). 'And he will rage as in the valley of Gibeon' (kaemeq begi'on yirgaz, he will be roused as in the valley of Gibeon) = Joshua 10:10-14 (the sun stood still, YHWH fought for Israel against the Amorites). But now YHWH fights against his own people: 'laashot ma'asehv zarr ma'asehv, to do his work, his alien work.' His 'strange/alien work' (zarr = alien/strange) = fighting against Israel is alien to his nature as Israel's champion. Lam 2:4-5 describes this: 'he has strung his bow... he has slain all who were pleasing to the eye; he has poured out his wrath like fire.'</p>",
    "22": "<p>'Now stop your mocking, or your bonds will grow tighter. I have heard from the Lord GOD of hosts a decree of complete destruction against the whole earth' — the urgent warning: 've'attah al-titshotzatsu pen-yechezequ moseireikhem, so now do not mock or your bonds/chains will grow tighter' (chazaq, become strong/tighten). The mocking of v.9-10 and v.14 is what is addressed: the scoffers are warned that continued mocking will tighten the bonds of their judgment. 'Ki khalah venecharatset shamati me'et adonay YHWH tseva'ot, for a decree of complete destruction I have heard from the Lord YHWH of hosts' (khalah venechratseth = complete destruction and determined judgment, the same vocabulary as 10:23: 'he will carry out his decreed destruction'). The universal scope: 'al-kol-ha'arets, against the whole land.'</p>",
    "23": "<p>'Listen and hear my voice; pay attention and hear what I say' — the introduction to the parable: 'haazinu vishme'u qoli, listen and hear my voice.' The double call for attention (haazin = lend your ear; shema = hear) before the agricultural parable that follows. The parable (vv.23-29) uses the farmer's wisdom to illustrate YHWH's differentiated, purposeful use of judgment. The structural function: after the woe-oracles against Ephraim and Jerusalem (vv.1-22), the parable explains that divine judgment operates like expert farming — with different treatments for different conditions, none of them random or excessive.</p>",
    "24": "<p>'Does a farmer spend the whole day plowing in order to plant? Does he keep breaking up the clods of his field forever?' — the first question of the parable: 'hayom kol-hayom yachresh hacharesh, does the farmer plow the whole day?' The rhetorical question expects 'no': plowing is a preparatory step, not an end in itself. 'Yiftach viyesaded admato, does he keep opening and harrowing his land?' (yesaded = break clods/harrow). The farmer does not plow endlessly — he plows for a purpose (planting) and then stops. The theological application: YHWH's judgment (plowing = breaking up) has a purpose and a limit. He does not judge forever — judgment prepares the soil for planting.</p>",
    "25": "<p>'When he has leveled the surface, he broadcasts caraway, scatters cumin, plants wheat in rows, barley in its proper place, and spelt along its edge' — the different planting methods for different seeds: 'halo im-shivah panav, does he not, when he has leveled its surface' (shivah = made smooth/level). 'Vehefitz qetsach, broadcast caraway (black cummin/nigella sativa)' — scattered broadcast. 'Vekhamon yizkeh, and scatter caraway' — in rows. 'Vesam chittah, and plant wheat' in rows (sorek = in a row). 'Use'orah nismam, and barley in its proper place' (nismam = in its designated area). 'Vekussemeth gevulato, and spelt along its border' (gevulato = its boundary/edge). Each grain has its optimal planting method — broadcast for small aromatic seeds, row-planting for large grains. The diversity of method reflects expertise.</p>",
    "26": "<p>'His God instructs him in the right way and teaches him' — the divine source of agricultural wisdom: 'veyissaro lemishpat Elohav yorennu, and his God instructs him in the right/justice of it; his God teaches him.' The farmer's expertise is YHWH's teaching (yorennu from yarah = to teach, the same root as Torah). The agricultural wisdom embedded in creation (the soil's response to different treatments, the optimal conditions for different crops) is YHWH's teaching built into the creation order. The farmer 'listens to' creation's instruction = listens to YHWH's instruction through nature. James 1:5 ('If any of you lacks wisdom, ask God, who gives generously to all') and Prov 8 (Lady Wisdom present at creation) are the same theology.</p>",
    "27": "<p>'Caraway is not threshed with a sledge, nor does a cartwheel roll over cumin. Caraway is beaten with a stick, and cumin with a rod' — the differentiated threshing methods: 'ki lo becharuts yudash qetsach, for with a threshing sledge caraway is not threshed' (charuts = a heavy threshing sledge with iron teeth that would destroy delicate seeds). 'Veofan agalah al-kamon, and a cartwheel does not roll over cumin.' Both aromatic seeds (qetsach = nigella sativa; kamon = cumin) are too delicate for heavy processing. 'Ki vechamel yuchat qetsach vehakamon beshevet, rather caraway is beaten with a stick and cumin with a rod' — gentle, precise processing appropriate to the seed. The theological application: YHWH uses the right instrument with the right force for the right crop — Israel's judgment is proportionate discipline, not the crushing judgment of the nations.</p>",
    "28": "<p>'Grain for bread must be crushed, but a farmer does not go on threshing it forever. He drives his cartwheel over it and lets horses trample it, but he does not grind it to powder' — the limit of threshing: 'lechem yudak, bread grain must be crushed' (yudak = must be beaten/crushed — the process is necessary). 'Ki lo lanetsach yidush lo, for he does not thresh it forever.' The farmer stops threshing at the right point — enough to separate grain from chaff, not so much as to grind the grain to powder. 'And he drives his horse-cart wheel over it but his horses do not grind it' (lo yedaqqenu, he does not crush it fine). The boundary of judgment: sufficient to accomplish the purpose (separate grain from chaff = separate the righteous remnant from the chaff of apostasy) but not excessive (not grinding to powder = not annihilation).</p>",
    "29": "<p>'All of this too comes from the LORD of hosts, whose counsel is wonderful and whose skill is great' — the closing attribution of agricultural wisdom to divine wisdom: 'gam-zot me'im YHWH tseva'ot yatsa, this too comes from YHWH of hosts.' The farmer's differentiated wisdom mirrors YHWH's differentiated governance of history. 'Hipli etsah, he has made wonderful counsel' (pele' etsah = wonderful plan/counsel — pele' is the same root as the Wonderful Counselor of 9:6). 'Higdil toushiyah, he has made great wisdom/skill' (toushiyah = productive wisdom, practical expertise that achieves its purpose). The parable's conclusion: YHWH's apparently harsh judgments are the work of the master-farmer who knows exactly how much threshing each crop needs and never applies more force than the purpose requires.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
